import {React, useState} from 'react';
import { registerFunc } from "../services/api"
import { useNavigate } from "react-router-dom";
import { ToastContainer, toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
const Register = () => {
    const navigation = useNavigate();
    const [form, setForm] = useState({
        name: "",
        username: "",
        email: "",
        password: "",
    })

    const [errors, setErrors] = useState(null)

    const handleInputChange = e => setForm({...form, [e.target.name]: e.target.value})

    const handleSubmit = async () => {
        if(!form.username || !form.password || !form.email || !form.name){
            toast.error("Please fill in all fields.");
            return;
        }

        try {
           const result = await registerFunc(form);
           console.log("API Response:", result);

           if(result.success){
            //successful register
            localStorage.setItem("user", JSON.stringify(result.data.data));
                            toast.success("Login successful!");
                            navigation("/", { replace: true });
           }else {
                           // Failed login
                    toast.error(result.error || "Regster failed. Please try again.");
                    setErrors(result.data);
                }
        } catch (error) {
            console.error("Login Error:", error);
            toast.error("An error occurred during login. Please try again.");
        }
    } 
    return(
        <div className="container">
            <div className="row justify-content-center mt-4">
                <div className="col-lg-5 card border-primary mt-4">
                    <div className="card-body">
                        <h4 className="card-title">Register Now</h4>
                        <form onSubmit={(e) => { e.preventDefault(); handleSubmit(); }}>
                        <div className="form-floating mb-3">
                                <input type="text" name="name" className="form-control" id="floatingInput" placeholder="username" onChange={handleInputChange}/>
                                <label htmlFor="floatingInput">Name</label>
                            </div>
                            <div className="form-floating mb-3">
                                <input type="text" name="username" className="form-control" id="floatingInput" placeholder="username" onChange={handleInputChange}/>
                                <label htmlFor="floatingInput">Username</label>
                            </div>
                            <div className="form-floating mb-3">
                                <input type="text" name="email" className="form-control" id="floatingInput" placeholder="username" onChange={handleInputChange} />
                                <label htmlFor="floatingInput">Email</label>
                            </div>
                            <div className="form-floating">
                                <input type="password" name="password" className="form-control" id="floatingPassword" placeholder="Password" autoComplete="off" onChange={handleInputChange} />
                                <label htmlFor="floatingPassword">Password</label>
                            </div>
                            <button type="submit" className="btn btn-primary mt-4">Register</button>
                        </form>
                    </div>
                </div>
            </div>
        </div>
    );

}

export default Register;


